module register_16bit(
    input clk,
    input reset,
    input load_enable,
    input [15:0] data_in,
    output reg [15:0] data_out
);
    always @(posedge clk or posedge reset) begin
        if (reset)
            data_out <= 16'd0;
        else if (load_enable)
            data_out <= data_in;
    end
  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        data_out <= 16'hFFFF;
      end
      else if (!load_enable) begin
        data_out <= data_out;
      end;
    end
  end

endmodule

